1	type Item = { type: string };
2	type Scenario = { steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	const RUNE_BASE_PER_ITEM = 25;
6	const RUNE_BLOCK_OF_THREE_BASE = 60;
7	
8	const PREMIUM_FOR_SINGLE_ITEM: Record<string, number> = {
9	  amulet: 71,
10	  staff: 93,
11	  potion: 49,
12	  sword: 115,
13	};
14	
15	export function runScenario(input: unknown): unknown {
16	  const { steps } = input as Scenario;
17	  const premium = computePremium(steps[0].items);
18	  return { results: [{ premium }] };
19	}
20	
21	function computePremium(items: Item[]): number {
22	  if (items.length === 0) return PROCESSING_FEE;
23	  if (items.every(isRune)) return runesPremium(items.length);
24	  return PREMIUM_FOR_SINGLE_ITEM[items[0].type];
25	}
26	
27	function runesPremium(count: number): number {
28	  const base = count === 3 ? RUNE_BLOCK_OF_THREE_BASE : count * RUNE_BASE_PER_ITEM;
29	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
30	}
31	
32	function isRune(item: Item): boolean {
33	  return item.type === "rune";
34	}
